import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"149. Underpayment Of Wages","description":"","frontmatter":{"title":"149. Underpayment Of Wages","eba":"Mental Health Services 2024-2028","topics":["wages"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/149-underpayment-of-wages.md","filePath":"ebas/mental-health/support-services/preliminary/149-underpayment-of-wages.md"}'),r={name:"ebas/mental-health/support-services/preliminary/149-underpayment-of-wages.md"};function s(p,e,i,l,m,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_149-underpayment-of-wages" tabindex="-1">149. Underpayment Of Wages <a class="header-anchor" href="#_149-underpayment-of-wages" aria-label="Permalink to &quot;149. Underpayment Of Wages&quot;">​</a></h1><p><strong>149.1</strong> Where an Employee considers that they have been underpaid as a result of error on the part of the Employer, the Employee may request that the Employer rectify the error or validate the payment.</p><p><strong>149.2</strong> Where an Employee is underpaid by reason of Employer error and the amount of such underpayment is less than 5% of the Employee’s fortnightly wage, the underpayment will be corrected in the next pay period.</p><p><strong>149.3</strong> Where the underpayment exceeds 5% of the Employee’s fortnightly wage, the Employer must take steps to correct the underpayment within 24 hours and to provide confirmation to the Employee of the correction.</p><p><strong>149.4</strong> Support Services Employees</p><p><strong>(a)</strong> If the Employer does not take the action required under clause 149.2 and clause</p><p><strong>149.3</strong> above, the Employee shall be paid a penalty payment of 20% of the underpayment, calculated on a daily basis from the date of the entitlement arising until all such moneys are paid. In addition, the Employer shall meet any associated banking or other fees/penalties incurred by the Employee as a consequence of the error where those fees exceed the 20% penalty payment.</p><p><strong>(b)</strong> Clause 149.4(a)will not come into effect:</p><p><strong>(i)</strong> if the payment of wages or other monies owed falls on a public holiday, until the expiration of such public holiday; or</p><p><strong>(ii)</strong> if any unforeseen event outside the control of the Employer frustrates their ability to meet the requirements of this clause.</p><p><strong>(c)</strong> Late payment on termination</p><p><strong>(i)</strong> When notice of termination of employment has been given by an Employee or an Employee’s services have been terminated by an Employer, payment of all wages and other monies owing to an Employee shall be made to the Employee.</p><p><strong>(ii)</strong> If an Employee is kept waiting for more than 24 hours such Employee shall be paid overtime rates for the duration of the period until such monies owing are paid, with a minimum payment of two (2) hours and a maximum payment of seven (7) hours and 36 minutes per day.</p>',13)])])}const f=t(r,[["render",s]]);export{d as __pageData,f as default};
